-- ============================================================================
-- Seed: CY2026 Medicare PFS FINAL RULE — full-document rule extraction.
--
-- Source: Federal Register 2025-19787 (90 FR 49266–50481, 1,216 pages),
-- "Medicare and Medicaid Programs; CY 2026 Payment Policies Under the
-- Physician Fee Schedule…" (CMS-1832-F). Effective 2026-01-01.
--
-- HOW THIS WAS PRODUCED: the full rule text (4.6 MB plain text; the
-- 211 MB PDF is 2x/6.6x over Claude's 600-page/32MB native-PDF limits) was
-- split into 44 overlapping slices and extracted by 44 parallel Claude agents
-- using the SAME contract as lib/ai/document-rule-extractor.ts (attribute
-- enum, coverage enum, code regex, verbatim source quotes). Every quote was
-- programmatically verified to appear verbatim in the source text
-- (anti-hallucination grounding); ungrounded rules were dropped. Deduped to
-- one row per (code, attribute).
--
-- 563 rules x 3 states (OH, NC, SC) for Traditional Medicare (Part B).
-- Applying this seed costs ZERO API tokens. For future rules (CY2027+), the
-- API pipeline is scripts/ingest-full-rule-chunked.mjs.
--
-- Prereqs:
--   sudo -u postgres psql pallio -f db/seed/payer-medicare.sql        (payer)
--   migration 0053 applied (same-day supersede, ships with normal deploy)
-- Apply:
--   sudo -u postgres psql pallio -f db/seed/payer-rules-cy2026-full-rule.sql
-- Idempotent: re-running replaces this seed's own rows.
-- ============================================================================

BEGIN;

-- 1. The source document (fixed id → idempotent).
  id, payer_id, url, document_type, title, effective_date,
  retrieved_at, content_hash, cms_license_token_used, source_metadata
)
SELECT
  'b0000000-0000-4000-8000-000000002026'::uuid,
  (SELECT id FROM payer WHERE name ILIKE '%medicare%'
    ORDER BY (payer_type = 'medicare_mac') DESC, created_at ASC LIMIT 1),
  'https://www.federalregister.gov/documents/2025/11/05/2025-19787/medicare-and-medicaid-programs-cy-2026-payment-policies-under-the-physician-fee-schedule-and-other',
  'cms_pfs',
  'CMS — CY2026 Physician Fee Schedule Final Rule (CMS-1832-F, 90 FR 49266)',
  DATE '2026-01-01', now(), 'sha256:bb2b7665e266c7b7ca3457721d2a949d8db1c3fd727f1e46cb1216486f413e7c', FALSE,
  '{"ingest":"full-rule-seed","fr_doc":"2025-19787","pages":"49266-50481"}'::jsonb
ON CONFLICT (id) DO UPDATE SET retrieved_at = now(), content_hash = EXCLUDED.content_hash;

-- 2. Idempotency: drop this seed's own prior rows (clean re-run).
DELETE FROM payer_rule WHERE source_doc_id = 'b0000000-0000-4000-8000-000000002026'::uuid;

-- 3. The extracted rules.
CREATE TEMP TABLE _cy2026_rules (
  code TEXT, attribute TEXT, coverage_status TEXT, value_json TEXT, source_quote TEXT
) ON COMMIT DROP;


-- 4. Supersede other documents' active rules for the same keys (the final
--    rule is the controlling authority). GREATEST() keeps expiration >=
--    effective for same-day rows (migration 0053).
UPDATE payer_rule pr
   SET expiration_date = GREATEST(CURRENT_DATE, pr.effective_date)
  FROM _cy2026_rules r
 WHERE pr.payer_id = (SELECT id FROM payer WHERE name ILIKE '%medicare%'
                       ORDER BY (payer_type = 'medicare_mac') DESC, created_at ASC LIMIT 1)
   AND pr.state = ANY(ARRAY['OH','NC','SC'])
   AND pr.code = r.code
   AND pr.attribute = r.attribute
   AND pr.expiration_date IS NULL
   AND pr.source_doc_id <> 'b0000000-0000-4000-8000-000000002026'::uuid;

-- 5. Insert: one row per rule per state.
  payer_id, state, product_line, code, attribute,
  value, coverage_status, confidence,
  effective_date, expiration_date,
  source_doc_id, source_quote, created_by
)
SELECT
  (SELECT id FROM payer WHERE name ILIKE '%medicare%'
    ORDER BY (payer_type = 'medicare_mac') DESC, created_at ASC LIMIT 1),
  s.state, 'commercial', r.code, r.attribute,
  r.value_json::jsonb, r.coverage_status, 0.95,
  DATE '2026-01-01', NULL,
  'b0000000-0000-4000-8000-000000002026'::uuid, r.source_quote, 'crawler:cms_pfs'
FROM _cy2026_rules r
CROSS JOIN (VALUES ('OH'),('NC'),('SC')) AS s(state);

-- 6. Mark the source document as extracted so /documents shows it correctly
-- (it produced the rules above; it didn't go through the live pipeline).
UPDATE source_document
   SET extracted_at = COALESCE(extracted_at, now()),
       extraction_candidate_count = (
         SELECT count(*)::int FROM payer_rule
         WHERE source_doc_id = 'b0000000-0000-4000-8000-000000002026'::uuid
       )
 WHERE id = 'b0000000-0000-4000-8000-000000002026'::uuid;

COMMIT;

-- Verify.
SELECT attribute, count(*) FROM payer_rule
 WHERE source_doc_id = 'b0000000-0000-4000-8000-000000002026'::uuid AND expiration_date IS NULL
 GROUP BY attribute ORDER BY count(*) DESC;
SELECT count(*) AS total_active_full_rule_rows FROM payer_rule
 WHERE source_doc_id = 'b0000000-0000-4000-8000-000000002026'::uuid AND expiration_date IS NULL;
