INSERT INTO source_document (
INSERT INTO _cy2026_rules (code, attribute, coverage_status, value_json, source_quote) VALUES
  ('0446T', 'units_per_period_max', 'covered', '{"answer":"HCPCS code 0446T is cited by CMS as a code with approximately 90 percent of its valuation based in practice expense that carries a Multiple Procedure (MPPR) indicator of \"2\", meaning payment is generally 100 percent of the highest valued procedure and 50 percent of the fee schedule amount for remaining billed procedures."}', 'which follow this pattern while also having a Multiple Procedure indicator of ``2'''' (such as CPT codes 19105, 27278, 33285, 47538, 55874, and HCPCS codes 0446T and 0448T).'),
  ('0448T', 'units_per_period_max', 'covered', '{"answer":"HCPCS code 0448T is cited by CMS as a code with approximately 90 percent of its valuation based in practice expense that carries a Multiple Procedure (MPPR) indicator of \"2\", meaning payment is generally 100 percent of the highest valued procedure and 50 percent of the fee schedule amount for remaining billed procedures."}', 'which follow this pattern while also having a Multiple Procedure indicator of ``2'''' (such as CPT codes 19105, 27278, 33285, 47538, 55874, and HCPCS codes 0446T and 0448T).'),
  ('0583T', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized national pricing for CPT code 0583T (tympanostomy using an automated tube delivery system, iontophoresis local anesthesia) via a direct crosswalk to the physician work, time, and direct PE input values of CPT code 31295."}', 'we are finalizing a crosswalk to the input values associated with CPT code 31295 for CPT code 0583T for CY 2026.'),
  ('0591T', 'units_per_period_max', 'varies', '{"answer":"Category III CPT code 0591T (Health and well-being coaching: face-to-face, individual initial assessment) is contractor-priced and has a January 2030 sunset date. Health coaches do not have a Medicare benefit category and cannot bill Medicare directly, but could potentially operate as clinical staff under general supervision incident-to a physician service."}', 'contractor-priced, and have a January 2030 sunset date.'),
  ('0592T', 'units_per_period_max', 'varies', '{"answer":"Category III CPT code 0592T (health coaching, individual follow-up session, at least 30 minutes) is contractor-priced and has a January 2030 sunset date. Health coaches do not have a Medicare benefit category and cannot bill Medicare directly."}', 'contractor-priced, and have a January 2030 sunset date.'),
  ('0593T', 'units_per_period_max', 'varies', '{"answer":"Category III CPT code 0593T (health coaching group session, two or more individuals, at least 30 minutes) is contractor-priced and has a January 2030 sunset date. Health coaches do not have a Medicare benefit category and cannot bill Medicare directly."}', 'contractor-priced, and have a January 2030 sunset date.'),
  ('0596T', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized as proposed (no public comments received) the RUC-recommended work RVU of 2.43 and RUC-recommended direct PE inputs without refinement for CPT code 0596T (temporary female intraurethral valve-pump, initial insertion including urethral measurement)."}', 'We proposed the RUC-recommended work RVU of 2.43 for CPT code 0596T and the RUC-recommended work RVU of 1.05 for CPT code 0597T.'),
  ('0597T', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized as proposed (no public comments received) the RUC-recommended work RVU of 1.05 and RUC-recommended direct PE inputs without refinement for CPT code 0597T (temporary female intraurethral valve-pump, insertion replacement)."}', 'We proposed the RUC-recommended work RVU of 2.43 for CPT code 0596T and the RUC-recommended work RVU of 1.05 for CPT code 0597T.'),
  ('0598T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0598T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', 'we proposed to include the following services on the list of codes to which the OPPS cap applies: CPT codes 0598T (Real-time fluorescence wound imaging with clinical darkness'),
  ('0599T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0599T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0599T (Real-time fluorescence wound imaging with clinical darkness, to identify location of bacterial wound pathogens and measure wound size, per session; each additional anatomic site'),
  ('0605T', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized national pricing for CPT code 0605T (remote patient-initiated OCT of retina with remote surveillance center technical support, minimum 8 daily recordings, each 30 days), replacing contractor pricing. CMS is establishing the inputs for 0605T using CPT code 93229 (mobile cardiovascular telemetry) as a direct crosswalk for valuation."}', 'finalizing national pricing for CPT code 0605T for CY 2026.'),
  ('0944T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0944T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0944T (3D contour simulation of target liver lesion(s) and margin(s) for image- guided percutaneous microwave ablation)'),
  ('0946T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0946T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0946T (Orthopedic implant movement analysis using paired computed tomography (CT) examination of the target structure'),
  ('0961T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0961T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0961T (Shortwave infrared radiation imaging, surgical pathology specimen, to assist gross examination for lymph node localization in fibroadipose tissue, per specimen'),
  ('0972T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0972T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0972T (Assistive algorithmic classification of burn healing (i.e., healing or nonhealing) by noninvasive multispectral imaging'),
  ('0984T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0984T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0984T (Intravascular imaging of extracranial cerebral vessels using optical coherence tomography (OCT) during diagnostic evaluation and/or therapeutic intervention, including all associated radiological supervision, interpretation, and report; initial vessel'),
  ('0985T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0985T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0985T (Intravascular imaging of extracranial cerebral vessels using optical coherence tomography (OCT) during diagnostic evaluation and/or therapeutic intervention, including all associated radiological supervision, interpretation, and report; each additional vessel'),
  ('0986T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0986T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0986T (Intravascular imaging of intracranial cerebral vessels using optical coherence tomography (OCT) during diagnostic evaluation and/or therapeutic intervention, including all associated radiological supervision, interpretation, and report; initial vessel'),
  ('0987T', 'units_per_period_max', 'covered', '{"answer":"For CY 2026, CPT code 0987T is added to the list of codes subject to the OPPS cap: the technical component of the PFS payment amount (prior to geographic adjustment) is capped at the OPPS payment amount for the service. CMS finalized the addition as proposed."}', '0987T (Intravascular imaging of intracranial cerebral vessels using optical coherence tomography (OCT) during diagnostic evaluation and/or therapeutic intervention, including all associated radiological supervision, interpretation, and report; each additional vessel'),
  ('10004', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 10004 (fine needle aspiration biopsy, without imaging guidance; each additional lesion) as potentially misvalued; its current valuation is retained."}', 'its next LOI for CY 2026, and we are finalizing our proposal not to'),
  ('10005', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 10005 (fine needle aspiration biopsy, including ultrasound guidance; first lesion) as potentially misvalued; its current work RVU (1.46) is retained. The RUC placed CPT codes 10005 and 10006 on its next Level of Interest to submit recommendations for CY 2027."}', 'its next LOI for CY 2026, and we are finalizing our proposal not to'),
  ('10006', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 10006 (fine needle aspiration biopsy, including ultrasound guidance; each additional lesion) as potentially misvalued; its current valuation is retained. The RUC placed CPT codes 10005 and 10006 on its next Level of Interest to submit recommendations for CY 2027."}', 'its next LOI for CY 2026, and we are finalizing our proposal not to'),
  ('10021', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 10021 (fine needle aspiration biopsy, without imaging guidance; first lesion) as potentially misvalued; its current work RVU (1.03) is retained rather than the RUC-recommended 1.20."}', 'its next LOI for CY 2026, and we are finalizing our proposal not to'),
  ('15011', 'covered', 'varies', '{"answer":"CPT code 15011 (skin cell suspension autograft) remains contractor priced for CY 2026; CMS declined to establish national pricing, citing unresolved concerns about service times, coding segmentation, and billing patterns of the add-on codes."}', 'We continue to believe contractor pricing is appropriate for these services and look forward to reviewing these codes again'),
  ('15012', 'covered', 'varies', '{"answer":"CPT code 15012 (skin cell suspension autograft) remains contractor priced for CY 2026; CMS declined to establish national pricing, citing unresolved concerns about service times, coding segmentation, and billing patterns of the add-on codes."}', 'We continue to believe contractor pricing is appropriate for these services and look forward to reviewing these codes again'),
  ('15013', 'covered', 'varies', '{"answer":"CPT code 15013 (skin cell suspension autograft) remains contractor priced for CY 2026; CMS declined to establish national pricing, citing unresolved concerns about service times, coding segmentation, and billing patterns of the add-on codes."}', 'We continue to believe contractor pricing is appropriate for these services and look forward to reviewing these codes again'),
  ('15014', 'covered', 'varies', '{"answer":"CPT code 15014 (skin cell suspension autograft) remains contractor priced for CY 2026; CMS declined to establish national pricing, citing unresolved concerns about service times, coding segmentation, and billing patterns of the add-on codes."}', 'We continue to believe contractor pricing is appropriate for these services and look forward to reviewing these codes again'),
  ('15015', 'covered', 'varies', '{"answer":"CPT code 15015 (skin cell suspension autograft) remains contractor priced for CY 2026; CMS declined to establish national pricing, citing unresolved concerns about service times, coding segmentation, and billing patterns of the add-on codes."}', 'We continue to believe contractor pricing is appropriate for these services and look forward to reviewing these codes again'),
  ('15016', 'covered', 'varies', '{"answer":"CPT code 15016 (skin cell suspension autograft) remains contractor priced for CY 2026; CMS declined to establish national pricing, citing unresolved concerns about service times, coding segmentation, and billing patterns of the add-on codes."}', 'We continue to believe contractor pricing is appropriate for these services and look forward to reviewing these codes again'),
  ('15017', 'covered', 'varies', '{"answer":"CPT code 15017 (skin cell suspension autograft) remains contractor priced for CY 2026; CMS declined to establish national pricing, citing unresolved concerns about service times, coding segmentation, and billing patterns of the add-on codes."}', 'We continue to believe contractor pricing is appropriate for these services and look forward to reviewing these codes again'),
  ('15018', 'covered', 'varies', '{"answer":"CPT code 15018 (skin cell suspension autograft) remains contractor priced for CY 2026; CMS declined to establish national pricing, citing unresolved concerns about service times, coding segmentation, and billing patterns of the add-on codes."}', 'We continue to believe contractor pricing is appropriate for these services and look forward to reviewing these codes again'),
  ('15271', 'bundled_with', 'covered', '{"answer":"CPT 15271 (application of skin substitute graft, leg or ankle) is an application base code reported together with the PE-only skin substitute product add-on code(s); under the finalized CY 2026 policy all skin substitute product codes are add-on codes (indicator ZZZ) billed with application codes like 15271, and the PE-only add-on codes are paid under the PFS only in the non-facility setting."}', 'CPT code 15271 (application of skin substitute graft, leg or ankle) would be reported with a PE-only add-on code that includes the resources involved in using the skin substitute product.'),
  ('15271', 'covered', 'covered', '{"answer":"CMS finalized that skin substitute products (other than section 351 BLA biologicals) used during the covered application procedure described by CPT 15271 are paid separately as incident-to supplies under the PFS in the non-facility setting starting January 1, 2026, instead of as biologicals under the ASP methodology; the initial CY 2026 payment rate for the products is approximately $125.38/cm2 across all three FDA regulatory categories."}', 'Because a skin substitute must be used to perform any of the procedures described by a CPT code in the range 15271 through 15278, and the procedure of treating the wound and applying a covering to the wound is the independent service, skin substitute products serve as a necessary supply for these surgical repair procedures.'),
  ('15272', 'covered', 'covered', '{"answer":"CMS finalized that skin substitute products (other than section 351 BLA biologicals) used during the covered application procedure described by CPT 15272 are paid separately as incident-to supplies under the PFS in the non-facility setting starting January 1, 2026, instead of as biologicals under the ASP methodology; the initial CY 2026 payment rate for the products is approximately $125.38/cm2 across all three FDA regulatory categories."}', 'we are finalizing our proposal to pay separately for the provision of skin substitutes as incident-to supplies under the PFS in the non-facility setting as proposed.'),
  ('15273', 'covered', 'covered', '{"answer":"CMS finalized that skin substitute products (other than section 351 BLA biologicals) used during the covered application procedure described by CPT 15273 are paid separately as incident-to supplies under the PFS in the non-facility setting starting January 1, 2026, instead of as biologicals under the ASP methodology; the initial CY 2026 payment rate for the products is approximately $125.38/cm2 across all three FDA regulatory categories."}', 'Because a skin substitute must be used to perform any of the procedures described by a CPT code in the range 15271 through 15278, and the procedure of treating the wound and applying a covering to the wound is the independent service, skin substitute products serve as a necessary supply for these surgical repair procedures.'),
  ('15274', 'covered', 'covered', '{"answer":"CMS finalized that skin substitute products (other than section 351 BLA biologicals) used during the covered application procedure described by CPT 15274 are paid separately as incident-to supplies under the PFS in the non-facility setting starting January 1, 2026, instead of as biologicals under the ASP methodology; the initial CY 2026 payment rate for the products is approximately $125.38/cm2 across all three FDA regulatory categories."}', 'we are finalizing our proposal to pay separately for the provision of skin substitutes as incident-to supplies under the PFS in the non-facility setting as proposed.'),
  ('15275', 'covered', 'covered', '{"answer":"CMS finalized that skin substitute products (other than section 351 BLA biologicals) used during the covered application procedure described by CPT 15275 are paid separately as incident-to supplies under the PFS in the non-facility setting starting January 1, 2026, instead of as biologicals under the ASP methodology; the initial CY 2026 payment rate for the products is approximately $125.38/cm2 across all three FDA regulatory categories."}', 'Because a skin substitute must be used to perform any of the procedures described by a CPT code in the range 15271 through 15278, and the procedure of treating the wound and applying a covering to the wound is the independent service, skin substitute products serve as a necessary supply for these surgical repair procedures.'),
  ('15276', 'covered', 'covered', '{"answer":"CMS finalized that skin substitute products (other than section 351 BLA biologicals) used during the covered application procedure described by CPT 15276 are paid separately as incident-to supplies under the PFS in the non-facility setting starting January 1, 2026, instead of as biologicals under the ASP methodology; the initial CY 2026 payment rate for the products is approximately $125.38/cm2 across all three FDA regulatory categories."}', 'we are finalizing our proposal to pay separately for the provision of skin substitutes as incident-to supplies under the PFS in the non-facility setting as proposed.'),
  ('15277', 'covered', 'covered', '{"answer":"CMS finalized that skin substitute products (other than section 351 BLA biologicals) used during the covered application procedure described by CPT 15277 are paid separately as incident-to supplies under the PFS in the non-facility setting starting January 1, 2026, instead of as biologicals under the ASP methodology; the initial CY 2026 payment rate for the products is approximately $125.38/cm2 across all three FDA regulatory categories."}', 'Because a skin substitute must be used to perform any of the procedures described by a CPT code in the range 15271 through 15278, and the procedure of treating the wound and applying a covering to the wound is the independent service, skin substitute products serve as a necessary supply for these surgical repair procedures.'),
  ('15278', 'covered', 'covered', '{"answer":"CMS finalized that skin substitute products (other than section 351 BLA biologicals) used during the covered application procedure described by CPT 15278 are paid separately as incident-to supplies under the PFS in the non-facility setting starting January 1, 2026, instead of as biologicals under the ASP methodology; the initial CY 2026 payment rate for the products is approximately $125.38/cm2 across all three FDA regulatory categories."}', 'we are finalizing our proposal to pay separately for the provision of skin substitutes as incident-to supplies under the PFS in the non-facility setting as proposed.'),
  ('15851', 'covered', 'covered', '{"answer":"CMS finalized a technical correction for CPT 15851 (removal of sutures or staples requiring anesthesia): the non-facility PE RVUs are removed for CY 2026, because the code has had no direct PE inputs since CMS finalized the RUC''s recommendation in the CY 2023 PFS final rule, making the continued assignment of non-facility PE RVUs an unintended technical error."}', 'concluded that the continued assignment of PE RVUs in the non-facility setting is an unintended technical error; we proposed to correct this code by removing the non-facility PE RVUs for CY 2026.'),
  ('19105', 'units_per_period_max', 'covered', '{"answer":"CPT 19105 is cited by CMS as a code with approximately 90 percent of its valuation based in practice expense that carries a Multiple Procedure (MPPR) indicator of \"2\", meaning payment is generally 100 percent of the highest valued procedure and 50 percent of the fee schedule amount for remaining billed procedures."}', 'which follow this pattern while also having a Multiple Procedure indicator of ``2'''' (such as CPT codes 19105, 27278, 33285, 47538, 55874, and HCPCS codes 0446T and 0448T).'),
  ('21076', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21076 (impression and custom preparation; surgical obturator prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21077', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21077 (impression and custom preparation; orbital prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21079', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21079 (impression and custom preparation; interim obturator prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21080', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21080 (impression and custom preparation; definitive obturator prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21081', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21081 (impression and custom preparation; mandibular resection prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21082', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21082 (impression and custom preparation; palatal augmentation prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21083', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21083 (impression and custom preparation; palatal lift prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21084', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21084 (impression and custom preparation; speech aid prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21085', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21085 (impression and custom preparation; oral surgical splint) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21086', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21086 (impression and custom preparation; auricular prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('21087', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 21087 (impression and custom preparation; nasal prosthesis) as potentially misvalued; its current work RVUs and practice expense inputs remain unchanged under the PFS."}', 'proposal not to nominate these codes as potentially misvalued.'),
  ('27278', 'units_per_period_max', 'covered', '{"answer":"CPT 27278 is cited by CMS as a code with approximately 90 percent of its valuation based in practice expense that carries a Multiple Procedure (MPPR) indicator of \"2\", meaning payment is generally 100 percent of the highest valued procedure and 50 percent of the fee schedule amount for remaining billed procedures."}', 'which follow this pattern while also having a Multiple Procedure indicator of ``2'''' (such as CPT codes 19105, 27278, 33285, 47538, 55874, and HCPCS codes 0446T and 0448T).'),
  ('27458', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized the RUC-recommended work RVU of 26.65 and direct PE inputs without refinement for CPT code 27458 (femur osteotomy with insertion of an externally controlled intramedullary lengthening device)."}', 'After consideration of public comments, we are finalizing our proposed values for CPT codes 27458, 27465, and 27466.'),
  ('27465', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized the RUC-recommended work RVU of 21.13 and direct PE inputs without refinement for CPT code 27465 (osteoplasty, femur; shortening)."}', 'After consideration of public comments, we are finalizing our proposed values for CPT codes 27458, 27465, and 27466.'),
  ('27466', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized the RUC-recommended work RVU of 22.65 and direct PE inputs without refinement for CPT code 27466 (osteoplasty, femur; lengthening)."}', 'After consideration of public comments, we are finalizing our proposed values for CPT codes 27458, 27465, and 27466.'),
  ('27468', 'covered', 'not_covered', '{"answer":"CPT code 27468 (osteoplasty, femur; combined lengthening and shortening with femoral segment transfer) is deleted for CY 2026; CMS finalized the deletion from Addendum B because the code will no longer exist in 2026."}', 'For CPT code 27468, we are finalizing the deletion of this code as it will no longer exist in 2026.'),
  ('27713', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized as proposed (no public comments received) the RUC-recommended work RVU of 28.00 and direct PE inputs without refinement for CPT code 27713 (tibia osteotomy with insertion of an externally controlled intramedullary lengthening device)."}', 'We proposed the RUC-recommended work RVU of 28.00 for CPT code 27713 and the work RVU of 22.50 for CPT 27715.'),
  ('27715', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized as proposed (no public comments received) the work RVU of 22.50 and direct PE inputs without refinement for CPT code 27715 (osteoplasty, tibia and fibula, lengthening or shortening)."}', 'We proposed the RUC-recommended work RVU of 28.00 for CPT code 27713 and the work RVU of 22.50 for CPT 27715.'),
  ('28750', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized the proposed RUC-recommended work RVU of 8.75 and RUC-recommended direct PE inputs for CPT code 28750 (arthrodesis, great toe; metatarsophalangeal joint)."}', 'After reviewing the comments, we are finalizing the proposed work RVU and direct PE inputs for CPT code 28750.'),
  ('28755', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized the RUC-recommended work RVU of 7.50 for CPT code 28755 (arthrodesis, great toe; interphalangeal joint), rejecting its own proposed lower work RVU of 6.76 after comments; RUC-recommended direct PE inputs also finalized."}', 'we are not finalizing our proposed work RVU of 6.76 for CPT code 28755 and we are instead finalizing the RUC-recommended work RVU of 7.50'),
  ('31000', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 31000 (lavage by cannulation; maxillary sinus) as potentially misvalued; the current PE valuation (supplies valued at $33.68) is retained and no increase for the Cyclone sinonasal irrigation device was adopted."}', 'proposal not to nominate nasal sinus irrigation (CPT codes 31000 and'),
  ('31002', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized its proposal not to nominate CPT code 31002 (lavage by cannulation; sphenoid sinus) as potentially misvalued; the code''s current valuation is retained, it continues to lack non-facility PE inputs, and CMS may consider feedback on non-facility payment in future rulemaking."}', 'proposal not to nominate nasal sinus irrigation (CPT codes 31000 and'),
  ('33285', 'units_per_period_max', 'covered', '{"answer":"CPT 33285 is cited by CMS as a code with approximately 90 percent of its valuation based in practice expense that carries a Multiple Procedure (MPPR) indicator of \"2\", meaning payment is generally 100 percent of the highest valued procedure and 50 percent of the fee schedule amount for remaining billed procedures."}', 'which follow this pattern while also having a Multiple Procedure indicator of ``2'''' (such as CPT codes 19105, 27278, 33285, 47538, 55874, and HCPCS codes 0446T and 0448T).'),
  ('33340', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized the RUC-recommended work RVU of 10.25 (down from 14.00) and RUC-recommended direct PE inputs without refinement for CPT code 33340 (percutaneous transcatheter closure of the left atrial appendage with endocardial implant)."}', 'After consideration of the public comments, we are finalizing our proposed work RVUs and direct PE inputs for CPT code 33340.'),
  ('33533', 'units_per_period_max', 'covered', '{"answer":"Under the finalized CY 2026 site-of-service policy reducing the portion of facility PE RVUs allocated based on work RVUs to half the amount allocated to non-facility PE RVUs, CPT 33533 (coronary artery bypass, single arterial graft; work RVU 33.75) drops from approximately 12 indirect PE RVUs in CY 2025 to approximately 7.2 indirect PE RVUs."}', 'indirect allocator, CPT code 33533 had approximately 12 indirect PE RVUs. Under this change to the methodology, where we will reduce the portion of the facility PE RVUs allocated based on work RVUs to half the amount allocated to non-facility PE RVUs, CPT code 33533 would have approximately 7.2 indirect PE RVUs.'),
  ('33880', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized a work RVU of 27.00 and RUC-recommended direct PE inputs for CPT code 33880 (endovascular repair of descending thoracic aorta involving coverage of left subclavian artery origin; crosswalked to CPT 32672, rejecting the RUC-recommended 30.00)."}', 'for CY 2026, we are finalizing our proposed work RVUs and direct PE inputs for CPT codes 33880, 33881, 33883, 33886, 33882 and 35602.'),
  ('33881', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized a work RVU of 22.53 and RUC-recommended direct PE inputs for CPT code 33881 (endovascular repair of descending thoracic aorta by aorto-aortic tube endograft not involving left subclavian coverage; crosswalked to CPT 43820, rejecting the RUC-recommended 26.75)."}', 'for CY 2026, we are finalizing our proposed work RVUs and direct PE inputs for CPT codes 33880, 33881, 33883, 33886, 33882 and 35602.'),
  ('33882', 'covered', 'covered', '{"answer":"For CY 2026, CMS finalized a work RVU of 35.00 and RUC-recommended direct PE inputs for CPT code 33882 (endovascular repair of thoracic aorta by branched endograft multipiece system; crosswalked to CPT 33390, rejecting the RUC-recommended 39.00)."}', 'for CY 2026, we are finalizing our proposed work RVUs and direct PE inputs for CPT codes 33880, 33881, 33883, 33886, 33882 and 35602.'),
